import{_ as t,o as l,c as a,a3 as s}from"./chunks/framework.DTo1Fhyx.js";const L=JSON.parse('{"title":"WSL 是什么？","description":"","frontmatter":{},"headers":[],"relativePath":"docs/UtilitySoftware/WSL/what-is-wsl.md","filePath":"docs/UtilitySoftware/WSL/what-is-wsl.md","lastUpdated":1731841950000}'),o={name:"docs/UtilitySoftware/WSL/what-is-wsl.md"};function e(n,i,r,u,d,w){return l(),a("div",null,i[0]||(i[0]=[s('<h1 id="what-is-wsl" tabindex="-1">WSL 是什么？ <a class="header-anchor" href="#what-is-wsl" aria-label="Permalink to &quot;WSL 是什么？ {#what-is-wsl}&quot;">​</a></h1><h2 id="wsl" tabindex="-1">Windows Subsystem for Linux <a class="header-anchor" href="#wsl" aria-label="Permalink to &quot;Windows Subsystem for Linux {#wsl}&quot;">​</a></h2><p><a href="https://learn.microsoft.com/zh-cn/windows/wsl/about" target="_blank" rel="noreferrer">什么是适用于 Linux 的 Windows 子系统？</a></p><p>适用于 Linux 的 Windows 子系统 (WSL) 是 Windows 的一项功能，可用于在 Windows 计算机上运行 Linux 环境，而无需单独的虚拟机或双引导。 WSL 旨在为希望同时使用 Windows 和 Linux 的开发人员提供无缝高效的体验。</p><ul><li>使用 WSL 安装和运行各种 Linux 发行版，例如 Ubuntu、Debian、Kali 等。 安装 Linux 发行版并从 Microsoft Store 接收自动更新、导入 Microsoft Store 中没有的 Linux 发行版，或构建你自己的定制 Linux 发行版。</li><li>将文件存储在独立的 Linux 文件系统中，具体取决于安装的发行版。</li><li>运行命令行工具，例如 BASH。</li><li>运行常用的 BASH 命令行工具（例如 grep、sed、awk）或其他 ELF-64 二进制文件。</li><li>运行 Bash 脚本和 GNU/Linux 命令行应用程序，包括：</li></ul><blockquote><ul><li>工具：vim、emacs、tmux</li><li>语言：NodeJS、JavaScript、Python、Ruby、C/C++、C# 和 F#、Rust、Go 等。</li><li>服务：SSHD、MySQL、Apache、lighttpd、MongoDB、PostgreSQL。</li></ul></blockquote><ul><li>使用自己的 GNU/Linux 分发包管理器安装其他软件。</li><li>使用类似于 Unix 的命令行 shell 调用 Windows 应用程序。</li><li>在 Windows 上调用 GNU/Linux 应用程序。</li><li>运行直接集成到 Windows 桌面的 GNU/Linux 图形应用程序</li><li>使用你的设备 GPU 加速 Linux 上运行的机器学习工作负载。</li></ul>',7)]))}const h=t(o,[["render",e]]);export{L as __pageData,h as default};
